console = Console()

class ToolRiskLevel(Enum):
    """Risk levels for tool operations"""
    SAFE = "safe"              # Read-only operations, queries
    LOW = "low"                # Small modifications, temporary changes
    MEDIUM = "medium"          # File modifications, environment changes
    HIGH = "high"              # System changes, destructive operations
    CRITICAL = "critical"      # Irreversible operations, security-sensitive

class ConfirmationGate(Enum):
    """Confirmation gate types"""
    NONE = "none"              # No confirmation needed
    IMPLICIT = "implicit"      # Implied consent from context
    EXPLICIT = "explicit"      # User must explicitly confirm
    MANDATORY = "mandatory"    # Always requires confirmation regardless of settings

@dataclass
class ToolOperation:
    """Represents a single tool operation with metadata"""
    tool_name: str
    operation: str
    parameters: Dict[str, Any]
    risk_level: ToolRiskLevel
    confirmation_gate: ConfirmationGate
    estimated_time: float = 0.0
    dependencies: List[str] = None
    rollback_possible: bool = True
    security_sensitive: bool = False

    def __post_init__(self):
        if self.dependencies is None:
            self.dependencies = []

@dataclass
class ToolChain:
    """Represents a sequence of related tool operations"""
    chain_id: str
    operations: List[ToolOperation]
    total_risk_score: float = 0.0
    requires_confirmation: bool = False
    estimated_total_time: float = 0.0
    parallel_capable: bool = False
    rollback_strategy: Optional[str] = None

@dataclass
class OrchestrationResult:
    """Result of tool orchestration"""
    chain_id: str
    success: bool
    operations_completed: int
    operations_failed: int
    total_time: float
    results: List[Dict] = None
    errors: List[str] = None
    rollback_performed: bool = False

    def __post_init__(self):
        if self.results is None:
            self.results = []
        if self.errors is None:
            self.errors = []

class AdvancedToolOrchestrator:
    """Advanced tool orchestration with intelligent planning and confirmation gates"""

    def _as_dict(self, obj, default=None):
        """Defensive helper to ensure object behaves like a dict"""
        if hasattr(obj, 'get') and callable(getattr(obj, 'get')):
            return obj
        return default or {}

    def __init__(self, tool_manager, config: Config):
        self.tool_manager = tool_manager
        self.config = config

        # Resource management
        self.resource_profile = resource_manager.get_profile_by_percentage(config.runtime.resources)
        self.time_slicer = TimeSlicedGenerator(self.resource_profile) if config.runtime.slice_generation else None

        # Risk assessment configuration
        self.risk_profiles = {
            # File Operations
            'file_read': ToolRiskLevel.SAFE,
            'file_write': ToolRiskLevel.MEDIUM,
            'file_edit': ToolRiskLevel.MEDIUM,
            'file_search': ToolRiskLevel.SAFE,
            'directory_list': ToolRiskLevel.SAFE,
            'file_copy': ToolRiskLevel.MEDIUM,
            'file_move': ToolRiskLevel.HIGH,
            'file_delete': ToolRiskLevel.HIGH,
            'file_create': ToolRiskLevel.MEDIUM,
            'file_fill': ToolRiskLevel.MEDIUM,
            # System Operations
            'bash_execute': ToolRiskLevel.HIGH,  # Dynamically adjusted based on command
            'grep_search': ToolRiskLevel.SAFE,
            'git_operations': ToolRiskLevel.MEDIUM,
            'change_directory': ToolRiskLevel.MEDIUM,
            'system_info': ToolRiskLevel.SAFE,
            'resource_request': ToolRiskLevel.SAFE,
            'process_manage': ToolRiskLevel.HIGH,
            # Research Operations
            'web_search': ToolRiskLevel.MEDIUM,
            'web_fetch': ToolRiskLevel.MEDIUM,
            # Development Operations
            'code_analyze': ToolRiskLevel.MEDIUM,
            'package_check': ToolRiskLevel.MEDIUM,
            # Meta Operations
            'think_time': ToolRiskLevel.MEDIUM,
        }

        # Confirmation gate rules
        self.confirmation_rules = {
            ToolRiskLevel.SAFE: ConfirmationGate.NONE,
            ToolRiskLevel.LOW: ConfirmationGate.IMPLICIT,
            ToolRiskLevel.MEDIUM: ConfirmationGate.EXPLICIT,
            ToolRiskLevel.HIGH: ConfirmationGate.EXPLICIT,
            ToolRiskLevel.CRITICAL: ConfirmationGate.MANDATORY,
        }

        # Operation tracking
        self.operation_history = []
        self.active_chains = {}

    def update_resource_profile(self):
        """Update resource profile when settings change"""
        self.resource_profile = resource_manager.get_profile_by_percentage(self.config.runtime.resources)
        if self.config.runtime.slice_generation:
            self.time_slicer = TimeSlicedGenerator(self.resource_profile)
        else:
            self.time_slicer = None

    def get_resource_status(self) -> Dict[str, Any]:
        """Get current resource status for diagnostics"""
        return {
            'resource_level': self.resource_profile.level.value,
            'description': self.resource_profile.description,
            'num_threads': self.resource_profile.num_threads,
            'max_context': self.resource_profile.max_context_tokens,
            'step_tokens': self.resource_profile.step_tokens,
            'memory_limit_mb': self.resource_profile.memory_limit_mb,
            'slice_enabled': self.time_slicer is not None,
            'active_chains': len(self.active_chains),
            'operations_in_history': len(self.operation_history)
        }

    async def analyze_tool_request(self, user_input: str, route_metadata: Dict) -> Optional[ToolChain]:
        """Analyze user request and plan optimal tool chain"""

        # Extract potential tool operations from input
        potential_ops = self._identify_tool_operations(user_input, route_metadata)

        if not potential_ops:
            return None

        # Create tool chain with optimization
        chain = self._create_optimized_chain(potential_ops, user_input)

        # Assess risks and confirmation requirements
        self._assess_chain_risks(chain)

        return chain

    def _identify_tool_operations(self, user_input: str, route_metadata: Dict) -> List[ToolOperation]:
        """Identify potential tool operations from user input"""
        operations = []

        # Pattern matching for common operations
        patterns = {
            'read': ['read', 'show', 'display', 'view', 'cat', 'examine'],
            'write': ['write', 'create', 'save', 'generate'],
            'edit': ['edit', 'modify', 'change', 'update', 'fix'],
            'search': ['search', 'find', 'grep', 'look', 'locate'],
            'execute': ['run', 'execute', 'command', 'bash', 'shell'],
            'list': ['list', 'ls', 'dir', 'show files', 'show directories'],
            'git': ['git', 'commit', 'push', 'pull', 'branch', 'checkout']
        }

        input_lower = user_input.lower()

        # File operation detection
        if any(word in input_lower for word in patterns['read']):
            if any(indicator in input_lower for indicator in ['file', 'content', '.py', '.js', '.txt']):
                operations.append(ToolOperation(
                    tool_name='file_read',
                    operation='read_file',
                    parameters={'file_path': self._extract_file_path(user_input)},
                    risk_level=self.risk_profiles.get('file_read', ToolRiskLevel.SAFE),
                    confirmation_gate=ConfirmationGate.NONE
                ))

        if any(word in input_lower for word in patterns['write']):
            operations.append(ToolOperation(
                tool_name='file_write',
                operation='write_file',
                parameters={'path': self._extract_file_path(user_input)},
                risk_level=self.risk_profiles.get('file_write', ToolRiskLevel.MEDIUM),
                confirmation_gate=ConfirmationGate.EXPLICIT
            ))

        if any(word in input_lower for word in patterns['search']):
            operations.append(ToolOperation(
                tool_name='grep_search',
                operation='search_content',
                parameters={'pattern': self._extract_search_pattern(user_input)},
                risk_level=self.risk_profiles.get('grep_search', ToolRiskLevel.SAFE),
                confirmation_gate=ConfirmationGate.NONE
            ))

        if any(word in input_lower for word in patterns['execute']):
            operations.append(ToolOperation(
                tool_name='bash_execute',
                operation='run_command',
                parameters={'command': self._extract_command(user_input)},
                risk_level=self.risk_profiles.get('bash_execute', ToolRiskLevel.HIGH),
                confirmation_gate=ConfirmationGate.EXPLICIT,
                security_sensitive=True
            ))

        # Directory listing operations
        if any(word in input_lower for word in patterns['list']) and any(indicator in input_lower for indicator in ['files', 'directory', 'dir', 'current']):
            operations.append(ToolOperation(
                tool_name='bash_execute',
                operation='list_directory',
                parameters={'command': 'ls -la'},
                risk_level=ToolRiskLevel.SAFE,
                confirmation_gate=ConfirmationGate.NONE
            ))

        return operations

    def _extract_file_path(self, text: str) -> str:
        """Extract file path from user input"""
        # Simple pattern matching - can be enhanced
        import re
        path_patterns = [
            r'[\'"]([^"\']+\.[a-zA-Z0-9]+)[\'"]',  # Quoted paths with extensions
            r'(\S+\.[a-zA-Z0-9]+)',                # Unquoted paths with extensions
            r'(/[\w\-_./]+)',                      # Unix-style paths
        ]

        for pattern in path_patterns:
            match = re.search(pattern, text)
            if match:
                return match.group(1)

        return ""

    def _extract_search_pattern(self, text: str) -> str:
        """Extract search pattern from user input"""
        # Look for quoted strings or common search indicators
        import re

        # Try to find quoted search terms
        quoted = re.search(r'[\'"]([^"\']+)[\'"]', text)
        if quoted:
            return quoted.group(1)

        # Look for 'for' keyword
        for_match = re.search(r'\bfor\s+(\w+)', text.lower())
        if for_match:
            return for_match.group(1)

        return ""

    def _extract_command(self, text: str) -> str:
        """Extract command from user input"""
        # Look for common command indicators
        import re

        command_patterns = [
            r'run\s+[\'"]([^"\']+)[\'"]',
            r'execute\s+[\'"]([^"\']+)[\'"]',
            r'command\s+[\'"]([^"\']+)[\'"]',
        ]

        for pattern in command_patterns:
            match = re.search(pattern, text, re.IGNORECASE)
            if match:
                return match.group(1)

        return ""

    def _create_optimized_chain(self, operations: List[ToolOperation], context: str) -> ToolChain:
        """Create optimized tool chain from operations"""
        if not operations:
            return None

        chain_id = f"chain_{datetime.now().strftime('%Y%m%d_%H%M%S')}"

        # Optimize operation order
        optimized_ops = self._optimize_operation_order(operations)

        # Calculate total estimated time
        total_time = sum(op.estimated_time for op in optimized_ops)

        # Determine if operations can run in parallel
        parallel_capable = self._can_run_parallel(optimized_ops)

        # Create rollback strategy
        rollback_strategy = self._create_rollback_strategy(optimized_ops)

        chain = ToolChain(
            chain_id=chain_id,
            operations=optimized_ops,
            estimated_total_time=total_time,
            parallel_capable=parallel_capable,
            rollback_strategy=rollback_strategy
        )

        return chain

    def _optimize_operation_order(self, operations: List[ToolOperation]) -> List[ToolOperation]:
        """Optimize the order of operations for efficiency and safety"""
        # Sort by risk level (safer operations first) and dependencies

        # Group by risk level
        risk_groups = {
            ToolRiskLevel.SAFE: [],
            ToolRiskLevel.LOW: [],
            ToolRiskLevel.MEDIUM: [],
            ToolRiskLevel.HIGH: [],
            ToolRiskLevel.CRITICAL: []
        }

        for op in operations:
            risk_groups[op.risk_level].append(op)

        # Optimize order: safe operations first, then by dependencies
        optimized = []
        for risk_level in [ToolRiskLevel.SAFE, ToolRiskLevel.LOW,
                          ToolRiskLevel.MEDIUM, ToolRiskLevel.HIGH, ToolRiskLevel.CRITICAL]:
            if risk_groups[risk_level]:
                # Sort by dependencies within risk level
                sorted_ops = self._sort_by_dependencies(risk_groups[risk_level])
                optimized.extend(sorted_ops)

        return optimized

    def _sort_by_dependencies(self, operations: List[ToolOperation]) -> List[ToolOperation]:
        """Sort operations by their dependencies"""
        # Simple topological sort
        sorted_ops = []
        remaining = operations.copy()

        while remaining:
            # Find operations with no unmet dependencies
            ready = []
            for op in remaining:
                if not op.dependencies or all(dep in [completed.tool_name for completed in sorted_ops] for dep in op.dependencies):
                    ready.append(op)

            if not ready:
                # Circular dependency or other issue - just add remaining
                sorted_ops.extend(remaining)
                break

            # Add ready operations
            for op in ready:
                sorted_ops.append(op)
                remaining.remove(op)

        return sorted_ops

    def _can_run_parallel(self, operations: List[ToolOperation]) -> bool:
        """Determine if operations can be run in parallel"""
        # Check for file conflicts, dependencies, and risk levels

        # High/critical risk operations should run sequentially
        if any(op.risk_level in [ToolRiskLevel.HIGH, ToolRiskLevel.CRITICAL] for op in operations):
            return False

        # Check for file path conflicts
        file_ops = [op for op in operations if 'file' in op.tool_name]
        if len(file_ops) > 1:
            paths = [self._as_dict(op.parameters).get('path', '') for op in file_ops]
            if len(set(paths)) < len(paths):  # Duplicate paths
                return False

        # Check dependencies
        if any(op.dependencies for op in operations):
            return False

        return True

    def _create_rollback_strategy(self, operations: List[ToolOperation]) -> Optional[str]:
        """Create rollback strategy for the operation chain"""
        reversible_ops = [op for op in operations if op.rollback_possible]

        if len(reversible_ops) == len(operations):
            return "full_rollback"
        elif reversible_ops:
            return "partial_rollback"
        else:
            return "no_rollback"

    def _assess_chain_risks(self, chain: ToolChain):
        """Assess risks and set confirmation requirements for the chain"""
        if not chain or not chain.operations:
            return

        # Calculate total risk score
        risk_weights = {
            ToolRiskLevel.SAFE: 0,
            ToolRiskLevel.LOW: 1,
            ToolRiskLevel.MEDIUM: 3,
            ToolRiskLevel.HIGH: 7,
            ToolRiskLevel.CRITICAL: 10
        }

        total_risk = sum(risk_weights[op.risk_level] for op in chain.operations)
        chain.total_risk_score = total_risk

        # Determine confirmation requirements
        requires_confirmation = False
        for op in chain.operations:
            gate = self.confirmation_rules.get(op.risk_level, ConfirmationGate.EXPLICIT)
            if gate in [ConfirmationGate.EXPLICIT, ConfirmationGate.MANDATORY]:
                requires_confirmation = True
                break
            elif gate == ConfirmationGate.IMPLICIT and self.config.interface.confirm_destructive:
                requires_confirmation = True
                break

        chain.requires_confirmation = requires_confirmation

    async def execute_tool_chain(self, chain: ToolChain) -> OrchestrationResult:
        """Execute a tool chain with proper orchestration"""
        if not chain:
            return OrchestrationResult(
                chain_id="unknown",
                success=False,
                operations_completed=0,
                operations_failed=1,
                total_time=0.0,
                errors=["No valid tool chain provided"]
            )

        start_time = datetime.now()

        # Create time budget based on resource profile and operation complexity
        estimated_total_time = sum(op.estimated_time for op in chain.operations)
        budget_multiplier = 1.0
        if self.resource_profile.level.value <= 25:
            budget_multiplier = 0.5  # Shorter budgets for fast mode
        elif self.resource_profile.level.value >= 75:
            budget_multiplier = 2.0  # Longer budgets for think mode

        time_budget = TimeBudget(
            total_seconds=max(30.0, estimated_total_time * budget_multiplier),
            started_at=time.time()
        )

        result = OrchestrationResult(
            chain_id=chain.chain_id,
            success=True,
            operations_completed=0,
            operations_failed=0,
            total_time=0.0
        )

        # Show execution plan
        await self._show_execution_plan(chain)

        # Get confirmation if required
        if chain.requires_confirmation:
            if not await self._get_user_confirmation(chain):
                result.success = False
                result.errors.append("User cancelled operation")
                return result

        # Store active chain
        self.active_chains[chain.chain_id] = chain

        try:
            # Execute operations with resource monitoring
            if chain.parallel_capable and len(chain.operations) > 1:
                result = await self._execute_parallel(chain, result, time_budget)
            else:
                result = await self._execute_sequential(chain, result, time_budget)

        except Exception as e:
            result.success = False
            result.errors.append(f"Execution error: {str(e)}")

            # Attempt rollback if possible
            if chain.rollback_strategy and chain.rollback_strategy != "no_rollback":
                console.print("[yellow]Attempting rollback...[/yellow]")
                await self._perform_rollback(chain)
                result.rollback_performed = True

        finally:
            # Calculate total time
            end_time = datetime.now()
            result.total_time = (end_time - start_time).total_seconds()

            # Remove from active chains
            if chain.chain_id in self.active_chains:
                del self.active_chains[chain.chain_id]

            # Store in history
            self.operation_history.append(result)

        return result

    async def _show_execution_plan(self, chain: ToolChain):
        """Display the execution plan to the user"""
        table = Table(title=f"🔧 Tool Execution Plan - {chain.chain_id}", show_header=True, header_style="bold cyan")
        table.add_column("Step", style="dim", width=6)
        table.add_column("Tool", style="cyan")
        table.add_column("Operation", style="green")
        table.add_column("Risk", style="yellow")
        table.add_column("Time", style="dim", width=8)

        for i, op in enumerate(chain.operations, 1):
            risk_color = {
                ToolRiskLevel.SAFE: "green",
                ToolRiskLevel.LOW: "blue",
                ToolRiskLevel.MEDIUM: "yellow",
                ToolRiskLevel.HIGH: "orange",
                ToolRiskLevel.CRITICAL: "red"
            }.get(op.risk_level, "white")

            table.add_row(
                str(i),
                op.tool_name,
                op.operation,
                f"[{risk_color}]{op.risk_level.value}[/{risk_color}]",
                f"{op.estimated_time:.1f}s"
            )

        console.print(table)

        # Show summary
        console.print(f"[dim]Total operations: {len(chain.operations)} | "
                     f"Estimated time: {chain.estimated_total_time:.1f}s | "
                     f"Risk score: {chain.total_risk_score} | "
                     f"Parallel: {'Yes' if chain.parallel_capable else 'No'}[/dim]")

    async def _get_user_confirmation(self, chain: ToolChain) -> bool:
        """Get user confirmation for tool chain execution"""

        # Show risk summary
        high_risk_ops = [op for op in chain.operations if op.risk_level in [ToolRiskLevel.HIGH, ToolRiskLevel.CRITICAL]]
        if high_risk_ops:
            console.print("\n[bold red]⚠️  High Risk Operations Detected:[/bold red]")
            for op in high_risk_ops:
                console.print(f"  • {op.tool_name}: {op.operation} ({op.risk_level.value})")
            console.print()

        # Get confirmation
        if chain.total_risk_score > 10:
            return Confirm.ask(f"[bold red]Execute this high-risk tool chain (risk score: {chain.total_risk_score})?[/bold red]")
        elif chain.total_risk_score > 5:
            return Confirm.ask(f"[yellow]Execute this tool chain (risk score: {chain.total_risk_score})?[/yellow]")
        else:
            return Confirm.ask("Execute this tool chain?")

    async def _execute_sequential(self, chain: ToolChain, result: OrchestrationResult, time_budget: TimeBudget) -> OrchestrationResult:
        """Execute operations sequentially with resource monitoring"""
        for i, operation in enumerate(chain.operations):
            # Check budget before each operation
            if time_budget.is_exceeded:
                console.print(f"[yellow]⏱️ Time budget exceeded, stopping at step {i+1}[/yellow]")
                result.errors.append(f"Time budget exceeded after {time_budget.elapsed:.1f}s")
                break

            console.print(f"[dim]Executing step {i+1}/{len(chain.operations)}: {operation.tool_name}[/dim]")

            # Show resource warning if approaching budget
            if time_budget.is_warning:
                console.print(f"[dim yellow]⚠ {time_budget.remaining:.1f}s remaining[/dim yellow]")

            try:
                # Execute the tool operation with resource monitoring
                step_start = time.time()
                tool_result = await self._execute_single_operation(operation)
                step_duration = time.time() - step_start

                result.results.append(tool_result)
                result.operations_completed += 1

                # Add small delay based on resource profile to prevent overload
                if self.resource_profile.slice_sleep_ms > 0:
                    await asyncio.sleep(self.resource_profile.slice_sleep_ms / 1000.0)

            except Exception as e:
                result.operations_failed += 1
                result.errors.append(f"Step {i+1} failed: {str(e)}")

                # Stop on high-risk operation failure
                if operation.risk_level in [ToolRiskLevel.HIGH, ToolRiskLevel.CRITICAL]:
                    result.success = False
                    break

        return result

    async def _execute_parallel(self, chain: ToolChain, result: OrchestrationResult, time_budget: TimeBudget) -> OrchestrationResult:
        """Execute operations in parallel where possible"""
        console.print("[dim]Executing operations in parallel...[/dim]")

        # Group operations that can run in parallel
        parallel_groups = self._group_for_parallel_execution(chain.operations)

        for group in parallel_groups:
            tasks = []
            for operation in group:
                task = asyncio.create_task(self._execute_single_operation(operation))
                tasks.append((operation, task))

            # Wait for all operations in the group to complete
            for operation, task in tasks:
                try:
                    tool_result = await task
                    result.results.append(tool_result)
                    result.operations_completed += 1
                except Exception as e:
                    result.operations_failed += 1
                    result.errors.append(f"Parallel operation {operation.tool_name} failed: {str(e)}")

        return result

    def _group_for_parallel_execution(self, operations: List[ToolOperation]) -> List[List[ToolOperation]]:
        """Group operations for parallel execution"""
        # Simple grouping - can be enhanced with more sophisticated dependency analysis
        groups = []
        current_group = []

        for op in operations:
            # Start new group for high-risk operations or operations with dependencies
            if (op.risk_level in [ToolRiskLevel.HIGH, ToolRiskLevel.CRITICAL] or
                op.dependencies or
                (current_group and any(existing.tool_name == op.tool_name for existing in current_group))):

                if current_group:
                    groups.append(current_group)
                current_group = [op]
            else:
                current_group.append(op)

        if current_group:
            groups.append(current_group)

        return groups

    async def _execute_single_operation(self, operation: ToolOperation) -> Dict:
        """Execute a single tool operation using the real ToolManager"""
        try:
            # Use the real tool manager to execute the operation
            result = await self.tool_manager.execute_tool(operation.tool_name, **operation.parameters)

            return {
                'tool': operation.tool_name,
                'operation': operation.operation,
                'parameters': operation.parameters,
                'success': result.success,
                'output': result.output if result.success else result.error,
                'error': result.error if not result.success else None,
                'metadata': getattr(result, 'metadata', {})
            }

        except Exception as e:
            return {
                'tool': operation.tool_name,
                'operation': operation.operation,
                'parameters': operation.parameters,
                'success': False,
                'output': None,
                'error': f"Execution failed: {str(e)}"
            }

    async def _perform_rollback(self, chain: ToolChain):
        """Perform rollback of completed operations"""
        console.print("[yellow]Performing rollback of completed operations...[/yellow]")

        # Reverse the order of completed operations
        completed_ops = [op for op in chain.operations if op.rollback_possible]

        for op in reversed(completed_ops):
            try:
                console.print(f"[dim]Rolling back: {op.tool_name}[/dim]")

                # Perform rollback based on tool type
                if op.tool_name == 'file_write' and 'backup_path' in op.parameters:
                    # Restore from backup
                    backup_path = op.parameters['backup_path']
                    original_path = op.parameters['file_path']
                    await self.tool_manager.execute_tool('bash_execute',
                                                       command=f'mv "{backup_path}" "{original_path}"')

                elif op.tool_name == 'file_edit' and 'original_content' in op.parameters:
                    # Restore original content
                    await self.tool_manager.execute_tool('file_write',
                                                       file_path=op.parameters['file_path'],
                                                       content=op.parameters['original_content'])

                elif op.tool_name == 'git_operations' and op.operation == 'commit':
                    # Reset the last commit (if safe)
                    await self.tool_manager.execute_tool('git_operations', operation='reset', mode='soft')

                else:
                    # Generic rollback - log that rollback is not implemented for this tool
                    console.print(f"[yellow]Rollback not implemented for {op.tool_name}[/yellow]")

            except Exception as e:
                console.print(f"[red]Rollback failed for {op.tool_name}: {e}[/red]")

    def get_orchestration_analytics(self) -> Dict:
        """Get analytics about tool orchestration performance"""
        if not self.operation_history:
            return {"message": "No orchestration history available"}

        total_chains = len(self.operation_history)
        successful_chains = sum(1 for result in self.operation_history if result.success)
        total_operations = sum(result.operations_completed for result in self.operation_history)
        avg_execution_time = sum(result.total_time for result in self.operation_history) / total_chains

        return {
            'total_chains_executed': total_chains,
            'success_rate': successful_chains / total_chains * 100,
            'total_operations_completed': total_operations,
            'average_execution_time': avg_execution_time,
            'rollbacks_performed': sum(1 for result in self.operation_history if result.rollback_performed)
        }

    # ========== MODEL-DRIVEN VALIDATION/ENHANCEMENT (Option 1) ==========

    async def validate_tool_call(self, tool_name: str, args: Dict[str, Any]) -> Dict[str, Any]:
        """Validate a model-emitted tool call before execution

        Returns:
            {
                'valid': bool,
                'risk_level': ToolRiskLevel,
                'confirmation_required': bool,
                'warnings': List[str],
                'enhanced_args': Dict[str, Any]  # Potentially improved parameters
                'suggested_fix': Optional[Dict]  # Alternative tool call if this one is invalid
            }
        """
        warnings = []
        enhanced_args = args.copy()
        suggested_fix = None

        # Check if tool exists in enabled tools
        available_tools = self.tool_manager.get_available_tools()
        if tool_name not in available_tools:
            # Common mistakes - suggest corrections
            if tool_name in ['find', 'ls', 'pwd', 'cat', 'grep', 'mkdir', 'touch']:
                # These are bash commands, not tool names
                command = tool_name
                if args:
                    # Reconstruct command intelligently based on tool type
                    if tool_name == 'find':
                        # find needs path and -name pattern
                        path = args.get('path', '.')
                        pattern = args.get('pattern', args.get('name', '*'))
                        command = f"find {path} -name '{pattern}'"
                    elif tool_name == 'ls':
                        path = args.get('path', '.')
                        command = f"ls -la {path}"
                    elif tool_name in ['cat', 'grep']:
                        # These need file/pattern arguments
                        if 'path' in args:
                            command = f"{tool_name} {args['path']}"
                        elif 'pattern' in args:
                            command = f"{tool_name} {args['pattern']}"
                    else:
                        # Generic: just append path/pattern if available
                        if 'path' in args:
                            command = f"{tool_name} {args['path']}"
                        elif 'pattern' in args:
                            command = f"{tool_name} {args['pattern']}"

                suggested_fix = {
                    'tool_name': 'bash_execute',
                    'args': {'command': command},
                    'reason': f"'{tool_name}' is a bash command, use bash_execute tool"
                }
                warnings.append(f"Tool '{tool_name}' does not exist. Use bash_execute with command='{command}'")
            else:
                warnings.append(f"Tool '{tool_name}' is not available. Available tools: {', '.join(available_tools)}")

            return {
                'valid': False,
                'risk_level': ToolRiskLevel.MEDIUM,
                'confirmation_required': False,
                'warnings': warnings,
                'enhanced_args': enhanced_args,
                'suggested_fix': suggested_fix
            }

        # Get risk level for this tool
        risk_level = self.risk_profiles.get(tool_name, ToolRiskLevel.MEDIUM)

        # Validate specific tool types
        if tool_name == 'file_write':
            # Check if file exists (overwrite risk)
            file_path = args.get('file_path') or args.get('path', '')
            if file_path:
                from pathlib import Path
                if Path(file_path).exists():
                    warnings.append(f"File {file_path} already exists - will be overwritten")
                    risk_level = ToolRiskLevel.MEDIUM

        elif tool_name == 'bash_execute':
            command = args.get('command', '').strip()

            # Safe read-only commands - downgrade to SAFE
            safe_commands = ['find ', 'ls ', 'pwd', 'whoami', 'date', 'cat ', 'head ', 'tail ', 'grep ', 'wc ']
            if any(command.startswith(cmd) for cmd in safe_commands):
                # Additional check: no pipes to dangerous commands
                if not any(danger in command.lower() for danger in ['rm', 'dd', 'format', '>', 'sudo', 'chmod', 'chown']):
                    risk_level = ToolRiskLevel.SAFE

            # Dangerous patterns - elevate to HIGH
            dangerous_patterns = ['rm -rf', 'rm -r', 'dd if=', 'format', 'sudo', 'chmod', 'chown']
            if any(pattern in command.lower() for pattern in dangerous_patterns):
                warnings.append(f"Dangerous command detected: {command}")
                risk_level = ToolRiskLevel.HIGH
            # Write/modify operations - keep as MEDIUM
            elif any(op in command for op in ['>', '>>', 'mv ', 'cp ']):
                risk_level = ToolRiskLevel.MEDIUM

        elif tool_name == 'file_edit':
            # Validate that old_text/new_text are present
            if not args.get('old_text') or not args.get('new_text'):
                warnings.append("file_edit requires both old_text and new_text parameters")
                return {
                    'valid': False,
                    'risk_level': risk_level,
                    'confirmation_required': False,
                    'warnings': warnings,
                    'enhanced_args': enhanced_args
                }

        elif tool_name in ['file_copy', 'file_move']:
            # Validate source and destination
            if not args.get('source') or not args.get('destination'):
                warnings.append(f"{tool_name} requires both source and destination parameters")
                return {
                    'valid': False,
                    'risk_level': risk_level,
                    'confirmation_required': False,
                    'warnings': warnings,
                    'enhanced_args': enhanced_args
                }
            from pathlib import Path
            if Path(args['destination']).exists():
                warnings.append(f"Destination {args['destination']} already exists - will be overwritten")
                risk_level = ToolRiskLevel.HIGH

        elif tool_name == 'file_delete':
            # Validate file_path exists
            if not args.get('file_path'):
                warnings.append("file_delete requires file_path parameter")
                return {
                    'valid': False,
                    'risk_level': risk_level,
                    'confirmation_required': False,
                    'warnings': warnings,
                    'enhanced_args': enhanced_args
                }
            warnings.append(f"IRREVERSIBLE: Will permanently delete {args['file_path']}")

        elif tool_name in ['file_create', 'file_fill']:
            # Validate file_path
            if not args.get('file_path'):
                warnings.append(f"{tool_name} requires file_path parameter")
                return {
                    'valid': False,
                    'risk_level': risk_level,
                    'confirmation_required': False,
                    'warnings': warnings,
                    'enhanced_args': enhanced_args
                }

        elif tool_name == 'process_manage':
            # Validate operation and warn for kill operations
            operation = args.get('operation', '')
            if operation == 'kill':
                warnings.append(f"Will terminate process {args.get('pid', 'unknown')}")
                risk_level = ToolRiskLevel.HIGH
            elif operation not in ['list', 'info', 'kill']:
                warnings.append(f"Invalid operation '{operation}'. Use: list, info, or kill")
                return {
                    'valid': False,
                    'risk_level': risk_level,
                    'confirmation_required': False,
                    'warnings': warnings,
                    'enhanced_args': enhanced_args
                }

        elif tool_name in ['web_search', 'web_fetch']:
            # Validate query/url parameter
            param = 'url' if tool_name == 'web_fetch' else 'query'
            if not args.get(param):
                warnings.append(f"{tool_name} requires {param} parameter")
                return {
                    'valid': False,
                    'risk_level': risk_level,
                    'confirmation_required': False,
                    'warnings': warnings,
                    'enhanced_args': enhanced_args
                }

        # Determine if confirmation required based on risk and settings
        confirmation_required = False
        gate = self.confirmation_rules.get(risk_level, ConfirmationGate.EXPLICIT)

        if gate in [ConfirmationGate.EXPLICIT, ConfirmationGate.MANDATORY]:
            confirmation_required = True
        elif gate == ConfirmationGate.IMPLICIT and self.config.interface.confirm_destructive:
            confirmation_required = True

        return {
            'valid': True,
            'risk_level': risk_level,
            'confirmation_required': confirmation_required,
            'warnings': warnings,
            'enhanced_args': enhanced_args,
            'suggested_fix': None
        }

    async def suggest_follow_up_tools(self, tool_name: str, tool_result: Dict,
                                      original_context: str) -> List[Dict[str, Any]]:
        """Suggest follow-up tools based on execution results

        Args:
            tool_name: Name of tool that just executed
            tool_result: Result from tool execution
            original_context: Original user request

        Returns:
            List of suggested follow-up tool calls:
            [
                {
                    'tool_name': str,
                    'reason': str,
                    'args': Dict[str, Any],
                    'priority': 'high'|'medium'|'low'
                }
            ]
        """
        suggestions = []

        # Analyze result success/failure
        success = tool_result.get('success', False)
        output = tool_result.get('output', '')
        error = tool_result.get('error', '')

        # Context-based suggestions
        if tool_name == 'grep_search' and success:
            # If grep found results, suggest reading those files
            if output and ':' in output:
                file_paths = set()
                for line in output.split('\n')[:5]:  # Limit to top 5 matches
                    if ':' in line:
                        file_path = line.split(':')[0]
                        file_paths.add(file_path)

                for file_path in file_paths:
                    suggestions.append({
                        'tool_name': 'file_read',
                        'reason': f'Read file containing search matches: {file_path}',
                        'args': {'file_path': file_path},
                        'priority': 'medium'
                    })

        elif tool_name == 'file_write' and success:
            # After writing a file, suggest verifying it was written correctly
            file_path = tool_result.get('file_path', '')
            if file_path:
                suggestions.append({
                    'tool_name': 'file_read',
                    'reason': f'Verify file was written correctly: {file_path}',
                    'args': {'file_path': file_path},
                    'priority': 'low'
                })

        elif tool_name == 'file_edit' and success:
            # After editing, suggest reading to confirm changes
            file_path = tool_result.get('file_path', '')
            if file_path:
                suggestions.append({
                    'tool_name': 'file_read',
                    'reason': f'Confirm edits applied correctly: {file_path}',
                    'args': {'file_path': file_path},
                    'priority': 'low'
                })

        elif not success:
            # If operation failed, suggest diagnostic tools
            if 'not found' in error.lower() or 'does not exist' in error.lower():
                suggestions.append({
                    'tool_name': 'bash_execute',
                    'reason': 'List current directory to locate files',
                    'args': {'command': 'ls -la'},
                    'priority': 'high'
                })

        return suggestions

    async def validate_tool_chain_post_execution(self, executed_tools: List[Dict],
                                                  original_intent: str) -> Dict[str, Any]:
        """Validate that executed tool chain achieved the intended goal

        Args:
            executed_tools: List of tools that were executed with their results
            original_intent: The original user request

        Returns:
            {
                'goal_achieved': bool,
                'confidence': float,  # 0.0 to 1.0
                'missing_steps': List[str],  # Steps that might be missing
                'recommendations': List[str]  # Suggested improvements
            }
        """
        goal_achieved = True
        confidence = 0.8  # Default moderate confidence
        missing_steps = []
        recommendations = []

        # Check if all tool executions succeeded
        failed_tools = [t for t in executed_tools if not t.get('success', False)]
        if failed_tools:
            goal_achieved = False
            confidence = 0.3
            missing_steps.append("Some tool executions failed")

        # Pattern-based analysis of intent vs execution
        intent_lower = original_intent.lower()

        # Check for read operations
        if any(word in intent_lower for word in ['show', 'read', 'display', 'what', 'check']):
            read_ops = [t for t in executed_tools if t.get('tool_name') == 'file_read']
            if not read_ops:
                confidence *= 0.7
                missing_steps.append("No file read operations performed for read-intent query")

        # Check for write operations
        if any(word in intent_lower for word in ['create', 'write', 'save']):
            write_ops = [t for t in executed_tools if t.get('tool_name') in ['file_write', 'file_edit']]
            if not write_ops:
                confidence *= 0.5
                missing_steps.append("No file write operations performed for write-intent query")

        # Check for search operations
        if any(word in intent_lower for word in ['find', 'search', 'grep', 'locate']):
            search_ops = [t for t in executed_tools if t.get('tool_name') == 'grep_search']
            if not search_ops:
                confidence *= 0.6
                missing_steps.append("No search operations performed for search-intent query")

        # Recommendations based on analysis
        if confidence < 0.5:
            recommendations.append("Consider using additional tools to fully address the request")

        if failed_tools:
            recommendations.append("Retry failed operations with corrected parameters")

        return {
            'goal_achieved': goal_achieved and confidence > 0.6,
            'confidence': confidence,
            'missing_steps': missing_steps,
            'recommendations': recommendations
        }